@page "/patients"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data

<PageTitle>Patients – VetClinic</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col">
        <input class="form-control" placeholder="Search patients..." @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowAddPatient">+ New Patient</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary me-2">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showOwnerForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPatientForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPatient.Id == 0 ? "Register Patient" : "Edit Patient")</div>
        <div class="card-body">
            <EditForm Model="editingPatient" OnValidSubmit="SavePatient" FormName="patientForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPatient.OwnerId">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPatient.Name" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="editingPatient.Species" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPatient.Breed" />
                    </div>
                    <div class="col-md-1 mb-2">
                        <label class="form-label">Sex</label>
                        <InputSelect class="form-select" @bind-Value="editingPatient.Sex">
                            <option value="">--</option>
                            <option>Male</option>
                            <option>Female</option>
                            <option>Neutered</option>
                            <option>Spayed</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPatient.WeightKg" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPatient.DateOfBirth" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Microchip #</label>
                        <InputText class="form-control" @bind-Value="editingPatient.MicrochipNumber" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary me-2">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showPatientForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
    @foreach (var p in patients)
    {
        <tr>
            <td>@p.Name</td>
            <td>@p.Species</td>
            <td>@p.Breed</td>
            <td>@p.Owner.FullName</td>
            <td>
                <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditPatient(p)">Edit</button>
                <button class="btn btn-sm btn-outline-info me-1" @onclick="() => ViewHistory(p)">History</button>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => DeletePatient(p)">Delete</button>
            </td>
        </tr>
    }
    </tbody>
</table>

@if (selectedPatient is not null)
{
    <div class="card mt-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span>Medical History – @selectedPatient.Name (@selectedPatient.Species)</span>
            <button class="btn btn-sm btn-success" @onclick="ShowAddTreatment">+ Add Treatment</button>
        </div>
        <div class="card-body">
            @if (showTreatmentForm)
            {
                <EditForm Model="editingTreatment" OnValidSubmit="SaveTreatment" FormName="treatmentForm" class="mb-3">
                    <DataAnnotationsValidator />
                    <ValidationSummary />
                    <div class="row">
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingTreatment.Date" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Description</label>
                            <InputText class="form-control" @bind-Value="editingTreatment.Description" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="editingTreatment.Diagnosis" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Performed By</label>
                            <InputText class="form-control" @bind-Value="editingTreatment.PerformedBy" />
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Medications</label>
                            <InputText class="form-control" @bind-Value="editingTreatment.Medications" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Notes</label>
                            <InputTextArea class="form-control" @bind-Value="editingTreatment.Notes" />
                        </div>
                    </div>
                    <button type="submit" class="btn btn-primary me-2">Save Treatment</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showTreatmentForm = false">Cancel</button>
                </EditForm>
            }

            @if (treatments.Count == 0)
            {
                <p class="text-muted">No treatments recorded yet.</p>
            }
            else
            {
                <table class="table table-sm">
                    <thead><tr><th>Date</th><th>Description</th><th>Diagnosis</th><th>Medications</th><th>By</th><th>Notes</th><th></th></tr></thead>
                    <tbody>
                    @foreach (var t in treatments)
                    {
                        <tr>
                            <td>@t.Date.ToString("g")</td>
                            <td>@t.Description</td>
                            <td>@t.Diagnosis</td>
                            <td>@t.Medications</td>
                            <td>@t.PerformedBy</td>
                            <td>@t.Notes</td>
                            <td><button class="btn btn-sm btn-outline-primary" @onclick="() => EditTreatment(t)">Edit</button></td>
                        </tr>
                    }
                    </tbody>
                </table>
            }
        </div>
    </div>
}

@code {
    private List<Patient> patients = [];
    private List<Owner> owners = [];
    private List<Treatment> treatments = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPatientForm, showTreatmentForm;
    private Owner editingOwner = new();
    private Patient editingPatient = new();
    private Treatment editingTreatment = new();
    private Patient? selectedPatient;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        await Search();
    }

    private async Task Search()
    {
        var query = Db.Patients.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(term)
                || p.Species.ToLower().Contains(term)
                || p.Owner.LastName.ToLower().Contains(term));
        }
        patients = await query.OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowAddOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
    }

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            Db.Owners.Add(editingOwner);
        await Db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private void ShowAddPatient()
    {
        editingPatient = new Patient();
        showPatientForm = true;
    }

    private void EditPatient(Patient p)
    {
        editingPatient = p;
        showPatientForm = true;
    }

    private async Task SavePatient()
    {
        if (editingPatient.Id == 0)
            Db.Patients.Add(editingPatient);
        await Db.SaveChangesAsync();
        showPatientForm = false;
        await LoadData();
    }

    private async Task DeletePatient(Patient p)
    {
        Db.Patients.Remove(p);
        await Db.SaveChangesAsync();
        if (selectedPatient?.Id == p.Id) selectedPatient = null;
        await LoadData();
    }

    private async Task ViewHistory(Patient p)
    {
        selectedPatient = p;
        treatments = await Db.Treatments
            .Where(t => t.PatientId == p.Id)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    private void ShowAddTreatment()
    {
        editingTreatment = new Treatment
        {
            PatientId = selectedPatient!.Id,
            Date = DateTime.Now
        };
        showTreatmentForm = true;
    }

    private void EditTreatment(Treatment t)
    {
        editingTreatment = t;
        showTreatmentForm = true;
    }

    private async Task SaveTreatment()
    {
        if (editingTreatment.Id == 0)
            Db.Treatments.Add(editingTreatment);
        await Db.SaveChangesAsync();
        showTreatmentForm = false;
        await ViewHistory(selectedPatient!);
    }
}

@page "/appointments"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data

<PageTitle>Appointments – VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">Week of</label>
        <input type="date" class="form-control" value="@weekStart.ToString("yyyy-MM-dd")" @onchange="ChangeWeek" />
    </div>
    <div class="col-md-3">
        <label class="form-label">Veterinarian</label>
        <input class="form-control" @bind="vetFilter" @bind:event="oninput" @bind:after="LoadAppointments" placeholder="All vets" />
    </div>
    <div class="col-auto d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowAdd">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editing.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editing" OnValidSubmit="Save" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                @if (!string.IsNullOrEmpty(conflictMessage))
                {
                    <div class="alert alert-danger">@conflictMessage</div>
                }
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="editing.PatientId">
                            <option value="0">-- Select --</option>
                            @foreach (var p in allPatients)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editing.StartTime" @bind-Value:after="CheckConflicts" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="editing.DurationMinutes" @bind-Value:after="CheckConflicts" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editing.VeterinarianName" @bind-Value:after="CheckConflicts" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="editing.Status">
                            @foreach (var s in Enum.GetValues<AppointmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editing.Reason" />
                    </div>
                    <div class="col-md-8 mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editing.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary me-2" disabled="@(!string.IsNullOrEmpty(conflictMessage))">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<!-- Weekly calendar grid -->
<div class="table-responsive">
    <table class="table table-bordered">
        <thead>
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day.Date == DateTime.Today ? "table-active" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-muted small">@TimeOnly.FromTimeSpan(TimeSpan.FromHours(hour)).ToString("h:mm tt")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotStart = weekStart.AddDays(d).AddHours(hour);
                        var slotEnd = slotStart.AddHours(1);
                        var slotAppts = appointments
                            .Where(a => a.StartTime < slotEnd && a.EndTime > slotStart && a.Status != AppointmentStatus.Cancelled)
                            .ToList();
                        <td class="small" style="min-width:120px;">
                            @foreach (var a in slotAppts)
                            {
                                var bgClass = a.Status switch
                                {
                                    AppointmentStatus.Completed => "bg-success-subtle",
                                    AppointmentStatus.NoShow => "bg-danger-subtle",
                                    _ => "bg-primary-subtle"
                                };
                                <div class="p-1 mb-1 rounded @bgClass" style="cursor:pointer" @onclick="() => EditAppointment(a)">
                                    <strong>@a.StartTime.ToString("h:mm")</strong> @a.Patient.Name<br/>
                                    <small>@a.VeterinarianName – @a.Reason</small>
                                </div>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart;
    private string vetFilter = "";
    private bool showForm;
    private Appointment editing = new();
    private string? conflictMessage;
    private List<Appointment> appointments = [];
    private List<Patient> allPatients = [];

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
        allPatients = await Db.Patients.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task ChangeWeek(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var d))
        {
            weekStart = d.AddDays(-(int)d.DayOfWeek);
            await LoadAppointments();
        }
    }

    private async Task LoadAppointments()
    {
        var weekEnd = weekStart.AddDays(7);
        var query = Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd);
        if (!string.IsNullOrWhiteSpace(vetFilter))
            query = query.Where(a => a.VeterinarianName.ToLower().Contains(vetFilter.ToLower()));
        appointments = await query.ToListAsync();
    }

    private void ShowAdd()
    {
        editing = new Appointment
        {
            StartTime = DateTime.Today.AddHours(DateTime.Now.Hour + 1),
            DurationMinutes = 30
        };
        conflictMessage = null;
        showForm = true;
    }

    private void EditAppointment(Appointment a)
    {
        editing = a;
        conflictMessage = null;
        showForm = true;
    }

    private async Task CheckConflicts()
    {
        if (string.IsNullOrWhiteSpace(editing.VeterinarianName))
        {
            conflictMessage = null;
            return;
        }
        var end = editing.StartTime.AddMinutes(editing.DurationMinutes);
        var conflict = await Db.Appointments
            .AnyAsync(a => a.Id != editing.Id
                && a.VeterinarianName == editing.VeterinarianName
                && a.Status == AppointmentStatus.Scheduled
                && a.StartTime < end
                && EF.Functions.Like(a.VeterinarianName, editing.VeterinarianName)
                && a.StartTime.AddMinutes(a.DurationMinutes) > editing.StartTime);
        conflictMessage = conflict ? "Conflict: this vet already has an appointment at that time." : null;
    }

    private async Task Save()
    {
        await CheckConflicts();
        if (!string.IsNullOrEmpty(conflictMessage)) return;

        if (editing.Id == 0)
            Db.Appointments.Add(editing);
        await Db.SaveChangesAsync();
        showForm = false;
        await LoadAppointments();
    }
}

@page "/billing"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data

<PageTitle>Billing – VetClinic</PageTitle>

<h1>Billing</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => { activeTab = "payments"; LoadPaymentHistory(); }'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowAddInvoice">+ New Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-3">
            <div class="card-header">@(editingInvoice.Id == 0 ? "New Invoice" : "Edit Invoice")</div>
            <div class="card-body">
                <EditForm Model="editingInvoice" OnValidSubmit="SaveInvoice" FormName="invoiceForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary />
                    <div class="row">
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Owner</label>
                            <InputSelect class="form-select" @bind-Value="editingInvoice.OwnerId" @bind-Value:after="OnOwnerChanged">
                                <option value="0">-- Select --</option>
                                @foreach (var o in owners)
                                {
                                    <option value="@o.Id">@o.FullName</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Patient (optional)</label>
                            <InputSelect class="form-select" @bind-Value="editingInvoice.PatientId">
                                <option value="">-- None --</option>
                                @foreach (var p in ownerPatients)
                                {
                                    <option value="@p.Id">@p.Name</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-2 mb-2">
                            <label class="form-label">Status</label>
                            <InputSelect class="form-select" @bind-Value="editingInvoice.Status">
                                @foreach (var s in Enum.GetValues<InvoiceStatus>())
                                {
                                    <option value="@s">@s</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-2 mb-2">
                            <label class="form-label">Due Date</label>
                            <InputDate class="form-control" @bind-Value="editingInvoice.DueDate" />
                        </div>
                    </div>

                    <h6 class="mt-2">Line Items</h6>
                    <table class="table table-sm">
                        <thead><tr><th>Description</th><th style="width:80px">Qty</th><th style="width:120px">Unit Price</th><th style="width:100px">Total</th><th style="width:50px"></th></tr></thead>
                        <tbody>
                        @foreach (var item in invoiceItems)
                        {
                            <tr>
                                <td><InputText class="form-control form-control-sm" @bind-Value="item.Description" /></td>
                                <td><InputNumber class="form-control form-control-sm" @bind-Value="item.Quantity" /></td>
                                <td><InputNumber class="form-control form-control-sm" @bind-Value="item.UnitPrice" /></td>
                                <td class="align-middle">@item.LineTotal.ToString("C")</td>
                                <td><button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => invoiceItems.Remove(item)">×</button></td>
                            </tr>
                        }
                        </tbody>
                    </table>
                    <button type="button" class="btn btn-sm btn-outline-secondary mb-2" @onclick="AddLineItem">+ Add Item</button>
                    <div class="fw-bold mb-3">Total: @invoiceItems.Sum(i => i.LineTotal).ToString("C")</div>

                    <button type="submit" class="btn btn-primary me-2">Save Invoice</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    <table class="table table-hover">
        <thead>
            <tr><th>#</th><th>Owner</th><th>Patient</th><th>Date</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
        @foreach (var inv in invoices)
        {
            <tr class="@(inv.Status == InvoiceStatus.Overdue ? "table-danger" : inv.Status == InvoiceStatus.Paid ? "table-success" : "")">
                <td>@inv.InvoiceNumber</td>
                <td>@inv.Owner.FullName</td>
                <td>@(inv.Patient?.Name ?? "—")</td>
                <td>@inv.CreatedDate.ToString("d")</td>
                <td>@inv.Total.ToString("C")</td>
                <td>@inv.AmountPaid.ToString("C")</td>
                <td>@inv.Balance.ToString("C")</td>
                <td><span class="badge @StatusBadge(inv.Status)">@inv.Status</span></td>
                <td>
                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditInvoice(inv)">Edit</button>
                    <button class="btn btn-sm btn-outline-success me-1" @onclick="() => ShowPayment(inv)">Pay</button>
                    @if (inv.Status != InvoiceStatus.Cancelled)
                    {
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelInvoice(inv)">Cancel</button>
                    }
                </td>
            </tr>
        }
        </tbody>
    </table>

    @if (showPaymentForm && paymentInvoice is not null)
    {
        <div class="card mb-3">
            <div class="card-header">Record Payment – Invoice @paymentInvoice.InvoiceNumber (Balance: @paymentInvoice.Balance.ToString("C"))</div>
            <div class="card-body">
                <EditForm Model="editingPayment" OnValidSubmit="SavePayment" FormName="paymentForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="editingPayment.Amount" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="editingPayment.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingPayment.PaidDate" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">
                                <InputCheckbox @bind-Value="editingPayment.IsRefund" /> Refund
                            </label>
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Notes</label>
                            <InputText class="form-control" @bind-Value="editingPayment.Notes" />
                        </div>
                    </div>
                    <button type="submit" class="btn btn-success me-2">Record Payment</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }
}
else
{
    <h4>Payment History</h4>
    <table class="table table-striped">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Type</th><th>Notes</th></tr>
        </thead>
        <tbody>
        @foreach (var p in paymentHistory)
        {
            <tr class="@(p.IsRefund ? "table-warning" : "")">
                <td>@p.PaidDate.ToString("g")</td>
                <td>@p.Invoice.InvoiceNumber</td>
                <td>@p.Invoice.Owner.FullName</td>
                <td>@p.Amount.ToString("C")</td>
                <td>@p.Method</td>
                <td>@(p.IsRefund ? "Refund" : "Payment")</td>
                <td>@p.Notes</td>
            </tr>
        }
        </tbody>
    </table>
}

@code {
    private string activeTab = "invoices";
    private List<Invoice> invoices = [];
    private List<Owner> owners = [];
    private List<Patient> ownerPatients = [];
    private List<Payment> paymentHistory = [];
    private bool showInvoiceForm, showPaymentForm;
    private Invoice editingInvoice = new();
    private List<InvoiceItem> invoiceItems = [];
    private Payment editingPayment = new();
    private Invoice? paymentInvoice;

    protected override async Task OnInitializedAsync()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        invoices = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Patient)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();
    }

    private void ShowAddInvoice()
    {
        var nextNum = (invoices.Count > 0)
            ? int.Parse(invoices.Max(i => i.InvoiceNumber)?.Replace("INV-", "") ?? "0") + 1
            : 1;
        editingInvoice = new Invoice
        {
            InvoiceNumber = $"INV-{nextNum:D5}",
            CreatedDate = DateTime.Now,
            DueDate = DateTime.Today.AddDays(30)
        };
        invoiceItems = [new InvoiceItem()];
        showInvoiceForm = true;
    }

    private void EditInvoice(Invoice inv)
    {
        editingInvoice = inv;
        invoiceItems = inv.Items.ToList();
        showInvoiceForm = true;
    }

    private void AddLineItem()
    {
        invoiceItems.Add(new InvoiceItem());
    }

    private async Task OnOwnerChanged()
    {
        ownerPatients = await Db.Patients
            .Where(p => p.OwnerId == editingInvoice.OwnerId)
            .ToListAsync();
    }

    private async Task SaveInvoice()
    {
        if (editingInvoice.Id == 0)
        {
            foreach (var item in invoiceItems)
                editingInvoice.Items.Add(item);
            Db.Invoices.Add(editingInvoice);
        }
        else
        {
            // Sync items
            var existing = await Db.InvoiceItems.Where(i => i.InvoiceId == editingInvoice.Id).ToListAsync();
            Db.InvoiceItems.RemoveRange(existing);
            foreach (var item in invoiceItems)
            {
                item.Id = 0;
                item.InvoiceId = editingInvoice.Id;
                Db.InvoiceItems.Add(item);
            }
        }
        await Db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        inv.Status = InvoiceStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadInvoices();
    }

    private void ShowPayment(Invoice inv)
    {
        paymentInvoice = inv;
        editingPayment = new Payment
        {
            InvoiceId = inv.Id,
            Amount = inv.Balance,
            PaidDate = DateTime.Now
        };
        showPaymentForm = true;
    }

    private async Task SavePayment()
    {
        Db.Payments.Add(editingPayment);
        await Db.SaveChangesAsync();

        // Update invoice status
        var inv = await Db.Invoices
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstAsync(i => i.Id == editingPayment.InvoiceId);
        inv.Status = inv.Balance <= 0 ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        await Db.SaveChangesAsync();

        showPaymentForm = false;
        await LoadInvoices();
    }

    private async Task LoadPaymentHistory()
    {
        paymentHistory = await Db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.PaidDate)
            .ToListAsync();
    }

    private string StatusBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-secondary",
        InvoiceStatus.PartiallyPaid => "bg-warning text-dark",
        InvoiceStatus.Sent => "bg-info",
        _ => "bg-primary"
    };
}

