@code {
    private int patientCount, ownerCount, todayAppointments, unpaidInvoices;
    private List<VetClinic.Data.Appointment> upcomingAppointments = [];
    private List<VetClinic.Data.Treatment> recentTreatments = [];

    protected override async Task OnInitializedAsync()
    {
        patientCount = await Db.Patients.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        todayAppointments = await Db.Appointments
            .CountAsync(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status == VetClinic.Data.AppointmentStatus.Scheduled);
        unpaidInvoices = await Db.Invoices
            .CountAsync(i => i.Status != VetClinic.Data.InvoiceStatus.Paid && i.Status != VetClinic.Data.InvoiceStatus.Cancelled);
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();
        recentTreatments = await Db.Treatments
            .Include(t => t.Patient)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}

