@code {
    private List<Patient> patients = [];
    private List<Owner> owners = [];
    private List<Treatment> treatments = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPatientForm, showTreatmentForm;
    private Owner editingOwner = new();
    private Patient editingPatient = new();
    private Treatment editingTreatment = new();
    private Patient? selectedPatient;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        await Search();
    }

    private async Task Search()
    {
        var query = Db.Patients.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(term)
                || p.Species.ToLower().Contains(term)
                || p.Owner.LastName.ToLower().Contains(term));
        }
        patients = await query.OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowAddOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
    }

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            Db.Owners.Add(editingOwner);
        await Db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private void ShowAddPatient()
    {
        editingPatient = new Patient();
        showPatientForm = true;
    }

    private void EditPatient(Patient p)
    {
        editingPatient = p;
        showPatientForm = true;
    }

    private async Task SavePatient()
    {
        if (editingPatient.Id == 0)
            Db.Patients.Add(editingPatient);
        await Db.SaveChangesAsync();
        showPatientForm = false;
        await LoadData();
    }

    private async Task DeletePatient(Patient p)
    {
        Db.Patients.Remove(p);
        await Db.SaveChangesAsync();
        if (selectedPatient?.Id == p.Id) selectedPatient = null;
        await LoadData();
    }

    private async Task ViewHistory(Patient p)
    {
        selectedPatient = p;
        treatments = await Db.Treatments
            .Where(t => t.PatientId == p.Id)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    private void ShowAddTreatment()
    {
        editingTreatment = new Treatment
        {
            PatientId = selectedPatient!.Id,
            Date = DateTime.Now
        };
        showTreatmentForm = true;
    }

    private void EditTreatment(Treatment t)
    {
        editingTreatment = t;
        showTreatmentForm = true;
    }

    private async Task SaveTreatment()
    {
        if (editingTreatment.Id == 0)
            Db.Treatments.Add(editingTreatment);
        await Db.SaveChangesAsync();
        showTreatmentForm = false;
        await ViewHistory(selectedPatient!);
    }
}

@page "/appointments"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data

<PageTitle>Appointments – VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">Week of</label>
        <input type="date" class="form-control" value="@weekStart.ToString("yyyy-MM-dd")" @onchange="ChangeWeek" />
    </div>
    <div class="col-md-3">
        <label class="form-label">Veterinarian</label>
        <input class="form-control" @bind="vetFilter" @bind:event="oninput" @bind:after="LoadAppointments" placeholder="All vets" />
    </div>
    <div class="col-auto d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowAdd">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editing.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editing" OnValidSubmit="Save" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                @if (!string.IsNullOrEmpty(conflictMessage))
                {
                    <div class="alert alert-danger">@conflictMessage</div>
                }
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="editing.PatientId">
                            <option value="0">-- Select --</option>
                            @foreach (var p in allPatients)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editing.StartTime" @bind-Value:after="CheckConflicts" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="editing.DurationMinutes" @bind-Value:after="CheckConflicts" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editing.VeterinarianName" @bind-Value:after="CheckConflicts" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="editing.Status">
                            @foreach (var s in Enum.GetValues<AppointmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editing.Reason" />
                    </div>
                    <div class="col-md-8 mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editing.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary me-2" disabled="@(!string.IsNullOrEmpty(conflictMessage))">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<!-- Weekly calendar grid -->
<div class="table-responsive">
    <table class="table table-bordered">
        <thead>
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day.Date == DateTime.Today ? "table-active" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-muted small">@TimeOnly.FromTimeSpan(TimeSpan.FromHours(hour)).ToString("h:mm tt")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotStart = weekStart.AddDays(d).AddHours(hour);
                        var slotEnd = slotStart.AddHours(1);
                        var slotAppts = appointments
                            .Where(a => a.StartTime < slotEnd && a.EndTime > slotStart && a.Status != AppointmentStatus.Cancelled)
                            .ToList();
                        <td class="small" style="min-width:120px;">
                            @foreach (var a in slotAppts)
                            {
                                var bgClass = a.Status switch
                                {
                                    AppointmentStatus.Completed => "bg-success-subtle",
                                    AppointmentStatus.NoShow => "bg-danger-subtle",
                                    _ => "bg-primary-subtle"
                                };
                                <div class="p-1 mb-1 rounded @bgClass" style="cursor:pointer" @onclick="() => EditAppointment(a)">
                                    <strong>@a.StartTime.ToString("h:mm")</strong> @a.Patient.Name<br/>
                                    <small>@a.VeterinarianName – @a.Reason</small>
                                </div>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart;
    private string vetFilter = "";
    private bool showForm;
    private Appointment editing = new();
    private string? conflictMessage;
    private List<Appointment> appointments = [];
    private List<Patient> allPatients = [];

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
        allPatients = await Db.Patients.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task ChangeWeek(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var d))
        {
            weekStart = d.AddDays(-(int)d.DayOfWeek);
            await LoadAppointments();
        }
    }

    private async Task LoadAppointments()
    {
        var weekEnd = weekStart.AddDays(7);
        var query = Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd);
        if (!string.IsNullOrWhiteSpace(vetFilter))
            query = query.Where(a => a.VeterinarianName.ToLower().Contains(vetFilter.ToLower()));
        appointments = await query.ToListAsync();
    }

    private void ShowAdd()
    {
        editing = new Appointment
        {
            StartTime = DateTime.Today.AddHours(DateTime.Now.Hour + 1),
            DurationMinutes = 30
        };
        conflictMessage = null;
        showForm = true;
    }

    private void EditAppointment(Appointment a)
    {
        editing = a;
        conflictMessage = null;
        showForm = true;
    }

    private async Task CheckConflicts()
    {
        if (string.IsNullOrWhiteSpace(editing.VeterinarianName))
        {
            conflictMessage = null;
            return;
        }
        var end = editing.StartTime.AddMinutes(editing.DurationMinutes);
        var conflict = await Db.Appointments
            .AnyAsync(a => a.Id != editing.Id
                && a.VeterinarianName == editing.VeterinarianName
                && a.Status == AppointmentStatus.Scheduled
                && a.StartTime < end
                && EF.Functions.Like(a.VeterinarianName, editing.VeterinarianName)
                && a.StartTime.AddMinutes(a.DurationMinutes) > editing.StartTime);
        conflictMessage = conflict ? "Conflict: this vet already has an appointment at that time." : null;
    }

    private async Task Save()
    {
        await CheckConflicts();
        if (!string.IsNullOrEmpty(conflictMessage)) return;

        if (editing.Id == 0)
            Db.Appointments.Add(editing);
        await Db.SaveChangesAsync();
        showForm = false;
        await LoadAppointments();
    }
}

