@code {
    private string activeTab = "invoices";
    private List<Invoice> invoices = [];
    private List<Owner> owners = [];
    private List<Patient> ownerPatients = [];
    private List<Payment> paymentHistory = [];
    private bool showInvoiceForm, showPaymentForm;
    private Invoice editingInvoice = new();
    private List<InvoiceItem> invoiceItems = [];
    private Payment editingPayment = new();
    private Invoice? paymentInvoice;

    protected override async Task OnInitializedAsync()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        invoices = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Patient)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();
    }

    private void ShowAddInvoice()
    {
        var nextNum = (invoices.Count > 0)
            ? int.Parse(invoices.Max(i => i.InvoiceNumber)?.Replace("INV-", "") ?? "0") + 1
            : 1;
        editingInvoice = new Invoice
        {
            InvoiceNumber = $"INV-{nextNum:D5}",
            CreatedDate = DateTime.Now,
            DueDate = DateTime.Today.AddDays(30)
        };
        invoiceItems = [new InvoiceItem()];
        showInvoiceForm = true;
    }

    private void EditInvoice(Invoice inv)
    {
        editingInvoice = inv;
        invoiceItems = inv.Items.ToList();
        showInvoiceForm = true;
    }

    private void AddLineItem()
    {
        invoiceItems.Add(new InvoiceItem());
    }

    private async Task OnOwnerChanged()
    {
        ownerPatients = await Db.Patients
            .Where(p => p.OwnerId == editingInvoice.OwnerId)
            .ToListAsync();
    }

    private async Task SaveInvoice()
    {
        if (editingInvoice.Id == 0)
        {
            foreach (var item in invoiceItems)
                editingInvoice.Items.Add(item);
            Db.Invoices.Add(editingInvoice);
        }
        else
        {
            // Sync items
            var existing = await Db.InvoiceItems.Where(i => i.InvoiceId == editingInvoice.Id).ToListAsync();
            Db.InvoiceItems.RemoveRange(existing);
            foreach (var item in invoiceItems)
            {
                item.Id = 0;
                item.InvoiceId = editingInvoice.Id;
                Db.InvoiceItems.Add(item);
            }
        }
        await Db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        inv.Status = InvoiceStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadInvoices();
    }

    private void ShowPayment(Invoice inv)
    {
        paymentInvoice = inv;
        editingPayment = new Payment
        {
            InvoiceId = inv.Id,
            Amount = inv.Balance,
            PaidDate = DateTime.Now
        };
        showPaymentForm = true;
    }

    private async Task SavePayment()
    {
        Db.Payments.Add(editingPayment);
        await Db.SaveChangesAsync();

        // Update invoice status
        var inv = await Db.Invoices
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstAsync(i => i.Id == editingPayment.InvoiceId);
        inv.Status = inv.Balance <= 0 ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        await Db.SaveChangesAsync();

        showPaymentForm = false;
        await LoadInvoices();
    }

    private async Task LoadPaymentHistory()
    {
        paymentHistory = await Db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.PaidDate)
            .ToListAsync();
    }

    private string StatusBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-secondary",
        InvoiceStatus.PartiallyPaid => "bg-warning text-dark",
        InvoiceStatus.Sent => "bg-info",
        _ => "bg-primary"
    };
}

