@page "/"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>Dashboard – VetClinic</PageTitle>

<h1>🐾 Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@patientCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Unpaid Invoices</h5>
                <p class="card-text display-6">@unpaidInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Count == 0)
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
        else
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Patient</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                @foreach (var apt in upcomingAppointments)
                {
                    <tr>
                        <td>@apt.StartTime.ToString("g")</td>
                        <td>@apt.Patient.Name</td>
                        <td>@apt.Reason</td>
                        <td>@apt.VeterinarianName</td>
                    </tr>
                }
                </tbody>
            </table>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Treatments</h4>
        @if (recentTreatments.Count == 0)
        {
            <p class="text-muted">No recent treatments.</p>
        }
        else
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Patient</th><th>Description</th><th>By</th></tr></thead>
                <tbody>
                @foreach (var t in recentTreatments)
                {
                    <tr>
                        <td>@t.Date.ToString("g")</td>
                        <td>@t.Patient.Name</td>
                        <td>@t.Description</td>
                        <td>@t.PerformedBy</td>
                    </tr>
                }
                </tbody>
            </table>
        }
    </div>
</div>

@code {
    private int patientCount, ownerCount, todayAppointments, unpaidInvoices;
    private List<VetClinic.Data.Appointment> upcomingAppointments = [];
    private List<VetClinic.Data.Treatment> recentTreatments = [];

    protected override async Task OnInitializedAsync()
    {
        patientCount = await Db.Patients.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        todayAppointments = await Db.Appointments
            .CountAsync(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status == VetClinic.Data.AppointmentStatus.Scheduled);
        unpaidInvoices = await Db.Invoices
            .CountAsync(i => i.Status != VetClinic.Data.InvoiceStatus.Paid && i.Status != VetClinic.Data.InvoiceStatus.Cancelled);
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();
        recentTreatments = await Db.Treatments
            .Include(t => t.Patient)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}

